import java.util.*;

class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

class Solution {
    public int minSwaps(TreeNode root) {
        int count = 0;
        Queue<Pair<TreeNode, Integer>> que = new LinkedList<>();
        que.add(new Pair<>(root, 0));

        List<Integer> levelVals = new ArrayList<>();
        int prevDepth = -1;

        while (!que.isEmpty()) {
            Pair<TreeNode, Integer> curr = que.remove();
            TreeNode node = curr.getKey();
            int depth = curr.getValue();

            if (prevDepth != depth) {
                Collections.sort(levelVals);
                for (int i = 1; i < levelVals.size(); ++i) {
                    count += Math.abs(levelVals.get(i) - levelVals.get(i-1)) - 1;
                }
                prevDepth = depth;
                levelVals.clear();
            }
            levelVals.add(node.val);

            if (node.left != null) que.add(new Pair<>(node.left, depth + 1));
            if (node.right != null) que.add(new Pair<>(node.right, depth + 1));
        }

        Collections.sort(levelVals);
        for (int i = 1; i < levelVals.size(); ++i) {
            count += Math.abs(levelVals.get(i) - levelVals.get(i-1)) - 1;
        }

        return count;
    }
}
```

